"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["2867"],{94320(e,i,t){t.r(i),t.d(i,{default:()=>s});var a=t(74848),r=t(47643),o=JSON.parse('{"id":13,"it":{"title":"Consigli di scrittura","prompt":"I want you to act as an AI writing tutor. I will provide you with a student who needs help improving their writing and your task is to use artificial intelligence tools, such as natural language processing, to give the student feedback on how they can improve their composition. You should also use your rhetorical knowledge and experience about effective writing techniques in order to suggest ways that the student can better express their thoughts and ideas in written form. Respond in Italian. My first request is [rivedere il testo]","description":"Vorrei che tu agissi come tutor di scrittura AI. Ti fornir\xf2 uno studente che ha bisogno di aiuto per migliorare la sua scrittura e il tuo compito sar\xe0 quello di utilizzare strumenti di intelligenza artificiale, come l\'elaborazione del linguaggio naturale, per dare allo studente un feedback su come migliorare la sua scrittura. Dovrai inoltre utilizzare le tue conoscenze di retorica e la tua esperienza sulle tecniche di scrittura efficaci per consigliare allo studente come esprimere meglio i suoi pensieri e le sue idee per iscritto. La mia prima richiesta \xe8 [rivedere il testo].","remark":"Fornisce opzioni e suggerimenti per il miglioramento della scrittura, ma non revisioni dirette del documento. (Personalmente, ritengo che sia adatto solo agli insegnanti per correggere i compiti)."},"tags":["write"],"website":"https://github.com/f/awesome-chatgpt-prompts#act-as-an-ai-writing-tutor","count":3241,"related":[{"id":2,"title":"Assistente di scrittura","remark":"Il prompt pi\xf9 usato, utilizzato per ottimizzare la sintassi, la chiarezza e la concisione del testo e migliorare la leggibilit\xe0."},{"id":209,"title":"Il Piccolo Libro Rosso dello Stile","remark":"Riscrivere il testo in uno stile Emoji simile a quello di Little Red Book."},{"id":197,"title":"Tocchi in stile natura","remark":"Verr\xe0 ritoccato in stile Nature, oppure si pu\xf2 fornire uno stile di scrittura che si vuole emulare. Contributo di @Pfyuan77."}],"metaTitle":"Tutor Scrittura AI: Feedback e Miglioramento","metaDescription":"Vuoi scrivere meglio? Ricevi feedback da un tutor IA con tecniche NLP per composizione, retorica ed espressione su misura.","faq":[{"q":"L\'AI pu\xf2 correggere direttamente il mio tema?","a":"No, non direttamente. Questo prompt \xe8 impostato come \xabfeedback da insegnante\xbb: segnala solo direzioni di miglioramento (struttura sfilacciata, argomentazioni deboli) ma non scrive al posto tuo. Se vuoi una riscrittura passa al prompt dell\'assistente di scrittura dell\'ID 2 o specifica \xabdammi direttamente il paragrafo corretto\xbb."},{"q":"Come ottenere feedback pi\xf9 concreti, punto per punto?","a":"Numera i paragrafi e poi scrivi \xabsegnala per ogni paragrafo 1-2 problemi pi\xf9 evidenti e proponi una frase sostitutiva d\'esempio\xbb. Senza numerazione ti dar\xe0 una valutazione d\'insieme che vale niente; numerazione pi\xf9 esempi trasformano il feedback da \xabvago\xbb in \xabazionabile\xbb."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T06:58:47+00:00"}');function s(){return(0,a.jsx)(r.A,{prompt:o,currentLanguage:"it"})}}}]);